INSERT INTO compliance.report_definitions
  (org_id, name, description, category, classifications, periodicity, periodicity_config, execution_type, execution_config, output_formats, status, data_gap_note, created_by)
VALUES
  (NULL, 'Sales Dashboard', 'Overall sales summary across leads, pipeline, quotations, orders and revenue.', 'software_report', '["sales","executive"]'::jsonb, 'daily', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- composite multi-table summary","aggregation":"count"}'::jsonb, '["table","chart"]'::jsonb, 'planned', 'Needs a composite summary across crm_leads/crm_opportunities/erp_quotations/erp_sales_orders/erp_sales_invoices beyond a single-table aggregation. Each component is separately reportable (see Lead Register, Sales Pipeline Report, Quotation Report, Won Projects Report, Revenue Booking Report) but no combined dashboard query is wired this wave.', 'system'),
  (NULL, 'Lead Register', 'All enquiries recorded in CRM, as returned by the real listLeads() service.', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'external_service', '{"kind":"external_service","sourceService":"crm-service.ts","sourceFunction":"listLeads","requiredParams":[]}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'New Leads Report', 'Leads broken down by source -- scheduled at a daily cadence to review recent intake.', 'software_report', '["sales"]'::jsonb, 'daily', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"crm_leads","tableKey":"crm_leads","aggregation":"count","groupByColumn":"source"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Lead Source Report', 'Leads broken down by source (Google/Facebook/Referral/Walk-in/Architect/Builder etc. -- free-text source column, not a closed list).', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"crm_leads","tableKey":"crm_leads","aggregation":"count","groupByColumn":"source"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Lead Status Report', 'Leads broken down by status (new/contacted/qualified/converted/lost).', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"crm_leads","tableKey":"crm_leads","aggregation":"count","groupByColumn":"status"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Sales Pipeline Report', 'Open opportunities broken down by pipeline stage (prospecting/proposal/negotiation/won/lost), with total estimated value per stage.', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"crm_opportunities","tableKey":"crm_opportunities","aggregation":"sum","groupByColumn":"stage","aggregationColumnKey":"estimatedValue"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Opportunity Report', 'Qualified opportunities broken down by owner, with count per salesperson.', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"crm_opportunities","tableKey":"crm_opportunities","aggregation":"count","groupByColumn":"ownerId"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Quotation Report', 'Quotations issued, broken down by status (draft/submitted/ordered/lost/expired).', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"erp_quotations","tableKey":"erp_quotations","aggregation":"count","groupByColumn":"status"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Quotation Pending Report', 'Quotations awaiting customer response (status = submitted), total value.', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"erp_quotations","tableKey":"erp_quotations","aggregation":"sum","groupByColumn":"customerId","aggregationColumnKey":"grandTotal","filterColumn":"status","filterValue":"submitted"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Quotation Follow-up Report', 'Upcoming follow-ups on pending quotations.', 'software_report', '["sales"]'::jsonb, 'daily', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no follow-up/next-action-date field on erp_quotations","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'erp_quotations has no follow-up-date or next-action field -- only quotation_date/valid_till. There is no scheduled-follow-up concept anywhere in the quotation schema to report against.', 'system'),
  (NULL, 'Quotation Revision Report', 'Revision history of quotations.', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no revision/version concept on erp_quotations","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'erp_quotations has no revision number, supersedes/parent-quotation pointer, or version history -- each row is a standalone quotation with no linkage to a prior version of itself.', 'system'),
  (NULL, 'Won Projects Report', 'Sales orders received, broken down by status -- includes completed (won) orders and their total value.', 'software_report', '["sales","revenue"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"erp_sales_orders","tableKey":"erp_sales_orders","aggregation":"sum","groupByColumn":"status","aggregationColumnKey":"grandTotal"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Lost Projects Report', 'Lost quotations and their count -- reasons for loss are not tracked.', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no loss-reason field anywhere","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'Neither erp_quotations nor crm_opportunities has a loss-reason/lost-reason-code column -- a count of lost quotations (status=''lost'') is derivable from Quotation Report, but ''reasons for loss'' has no backing data anywhere in the schema.', 'system'),
  (NULL, 'Salesperson Performance Report', 'Won sales orders and total revenue, broken down by owner -- via opportunity ownerId on the linked opportunity, not directly on the order.', 'software_report', '["sales","executive"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"crm_opportunities","tableKey":"crm_opportunities","aggregation":"sum","groupByColumn":"ownerId","aggregationColumnKey":"estimatedValue","filterColumn":"stage","filterValue":"won"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Daily Sales Activity Report', 'Calls, meetings, site visits logged by sales staff.', 'software_report', '["sales"]'::jsonb, 'daily', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no activity-type field distinguishing calls/meetings/site-visits","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'No table tags an activity as a call, meeting, or site visit for sales purposes. tasks has no ''type'' column; veri_meetings has meeting_type (''team''|''client''|''vendor''|''one_on_one''|''other'') which can proxy client MEETINGS only (see Customer Meeting Report) but has no ''call'' or ''site visit'' concept at all.', 'system'),
  (NULL, 'Customer Meeting Report', 'Meeting summaries for client meetings (veri_meetings.meeting_type = ''client'').', 'software_report', '["sales","customer"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"veri_meetings","tableKey":"veri_meetings","aggregation":"count","groupByColumn":"contextEntityType","filterColumn":"meetingType","filterValue":"client"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Site Visit Report', 'Site inspections conducted before quotation.', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no site-visit tracking table","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'No table records a pre-sale site visit as a distinct event -- pms_meetings requires an existing project_id (post-sale), and veri_meetings has no site-visit meeting_type. There is no pre-quotation site-inspection concept in the schema.', 'system'),
  (NULL, 'Proposal Status Report', 'Opportunities currently at the proposal stage.', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"crm_opportunities","tableKey":"crm_opportunities","aggregation":"count","groupByColumn":"ownerId","filterColumn":"stage","filterValue":"proposal"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Contract Status Report', 'Opportunities currently under negotiation.', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"crm_opportunities","tableKey":"crm_opportunities","aggregation":"count","groupByColumn":"ownerId","filterColumn":"stage","filterValue":"negotiation"}'::jsonb, '["table"]'::jsonb, 'built', 'Uses crm_opportunities.stage = ''negotiation'' as the proxy for "contract under negotiation" -- there is no separate contract/agreement document-status table for pre-sale contracts (erp_contracts exists but is a post-award vendor-contract table, a different concept).', 'system'),
  (NULL, 'Sales Forecast Report', 'Estimated value of opportunities broken down by pipeline stage -- a real but simplified stand-in for a full weighted revenue forecast.', 'software_analysis', '["sales","predictive"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"crm_opportunities","tableKey":"crm_opportunities","aggregation":"sum","groupByColumn":"stage","aggregationColumnKey":"estimatedValue"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Revenue Booking Report', 'Confirmed revenue -- sales invoices broken down by status, total grand_total.', 'software_report', '["sales","revenue"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"erp_sales_invoices","tableKey":"erp_sales_invoices","aggregation":"sum","groupByColumn":"status","aggregationColumnKey":"grandTotal"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Booking vs Target Report', 'Achievement against a sales target.', 'software_analysis', '["sales","revenue","executive"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no sales-target table","aggregation":"count"}'::jsonb, '["table","chart"]'::jsonb, 'data_gap', 'No table stores a sales target (org-level, team-level, or per-salesperson) anywhere in the schema -- actual bookings are reportable (Revenue Booking Report) but there is nothing to compare them against.', 'system'),
  (NULL, 'Commission Report', 'Sales incentive calculation -- referred deal value and commission accrued, by partner.', 'software_report', '["sales","revenue"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_formula', '{"kind":"formula","formulaKey":"referral_revenue_summary"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Customer Follow-up Report', 'Pending customer communication.', 'software_report', '["sales","customer"]'::jsonb, 'daily', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no follow-up/next-contact-date field on any customer-facing entity","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'No table has a scheduled follow-up / next-contact-date field for a customer or lead -- crm_leads/crm_opportunities/erp_quotations all lack a next-action-date concept.', 'system'),
  (NULL, 'Repeat Customer Report', 'Customers with more than one completed sales order.', 'software_report', '["sales","customer"]'::jsonb, 'on_demand', NULL, 'deterministic_formula', '{"kind":"formula","formulaKey":"repeat_customer_percentage"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Referral Report', 'Referral-generated business -- referred deal value and commission, by partner.', 'software_report', '["sales","revenue"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_formula', '{"kind":"formula","formulaKey":"referral_revenue_summary"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Customer Complaint Report', 'Pre-sales and post-sales customer issues.', 'software_report', '["sales","customer"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no complaint/support-ticket table","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'No support-ticket, complaint, or issue-log table exists for customer-facing (as opposed to internal pms_issues, which is project-task tracking) complaints anywhere in the schema.', 'system'),
  (NULL, 'Project Handover Report', 'Projects handed over to delivery/execution.', 'software_report', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- construction project handover is another agent''s domain","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'planned', 'Project handover status is construction-domain (projects table + PROJEXA modules), owned by a parallel agent''s report_definitions rows this same wave -- not duplicated here to avoid conflicting definitions of the same concept.', 'system'),
  (NULL, 'Customer Feedback Report', 'Ratings and comments from customers.', 'software_report', '["sales","customer"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no feedback/rating table","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'No table stores a customer rating, review, or feedback comment anywhere in the schema.', 'system'),
  (NULL, 'Sales Closure Report', 'Monthly sales closure summary -- completed orders and invoiced revenue for the period.', 'software_report', '["sales","revenue","executive"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"erp_sales_orders","tableKey":"erp_sales_orders","aggregation":"sum","groupByColumn":"status","aggregationColumnKey":"grandTotal"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Lead Conversion Analysis', 'Lead -> Customer conversion rate, based on crm_leads.converted_client_id.', 'software_analysis', '["sales","predictive"]'::jsonb, 'weekly', '{"dayOfWeek":1}'::jsonb, 'deterministic_formula', '{"kind":"formula","formulaKey":"lead_conversion_rate"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Sales Funnel Analysis', 'Opportunity count by stage -- the real stage breakdown a drop-off funnel is built from.', 'software_analysis', '["sales"]'::jsonb, 'weekly', '{"dayOfWeek":1}'::jsonb, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"crm_opportunities","tableKey":"crm_opportunities","aggregation":"count","groupByColumn":"stage"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Lead Source ROI', 'Best-performing marketing channels by cost.', 'software_analysis', '["sales","predictive"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no channel-cost/marketing-spend table","aggregation":"count"}'::jsonb, '["table","chart"]'::jsonb, 'data_gap', 'No table records marketing/channel spend anywhere in the schema -- Lead Source Report shows lead COUNT per source, but ROI requires a cost-per-channel figure that does not exist, so a true ROI cannot be computed, only fabricated.', 'system'),
  (NULL, 'Sales Cycle Analysis', 'Average time to close, from lead creation to a completed sales order that traces back through a quotation.', 'software_analysis', '["sales"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_formula', '{"kind":"formula","formulaKey":"sales_cycle_length_days"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Quotation Win Rate', 'Won quotations as a percentage of all decided (ordered/lost/expired) quotations.', 'software_analysis', '["sales"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_formula', '{"kind":"formula","formulaKey":"quotation_win_rate"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Quotation Loss Analysis', 'Why quotations are rejected.', 'software_analysis', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no loss-reason field on erp_quotations","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'erp_quotations has no loss-reason/rejection-reason column -- lost-quotation COUNT is derivable (Quotation Report), but not WHY.', 'system'),
  (NULL, 'Salesperson Productivity', 'Won-opportunity value per owner.', 'software_analysis', '["sales","executive"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"crm_opportunities","tableKey":"crm_opportunities","aggregation":"sum","groupByColumn":"ownerId","aggregationColumnKey":"estimatedValue","filterColumn":"stage","filterValue":"won"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Sales Target Achievement', 'Target vs actual sales achievement.', 'software_analysis', '["sales","executive"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no sales-target table","aggregation":"count"}'::jsonb, '["table","chart"]'::jsonb, 'data_gap', 'Same gap as Booking vs Target Report -- no sales-target table exists anywhere in the schema.', 'system'),
  (NULL, 'Revenue Trend Analysis', 'Sales invoice revenue broken down by status -- a monthly/yearly time trend needs date-bucketing beyond this engine''s current groupBy-on-a-single-column aggregation.', 'software_analysis', '["sales","revenue"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"erp_sales_invoices","tableKey":"erp_sales_invoices","aggregation":"sum","groupByColumn":"status","aggregationColumnKey":"grandTotal"}'::jsonb, '["table","chart"]'::jsonb, 'planned', 'erp_sales_invoices.posting_date is real and queryable, but a month/year TREND needs date_trunc-style bucketing, which the current TABLE_REGISTRY-backed aggregation (a plain single-column groupBy) does not support -- only the status breakdown is wired this wave.', 'system'),
  (NULL, 'Profitability Analysis', 'Profit by project.', 'software_analysis', '["sales","revenue"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- project-level profitability is construction-domain (erp_budgets/erp_cost_centers)","aggregation":"count"}'::jsonb, '["table","chart"]'::jsonb, 'planned', 'Project-level cost/budget data (erp_budgets, erp_cost_centers, construction_expense_entries) is construction-domain, covered by the parallel construction-reports agent''s Budget vs Actual / project profitability definitions this same wave -- not duplicated here.', 'system'),
  (NULL, 'Customer Acquisition Cost (CAC)', 'Cost to acquire customers.', 'software_analysis', '["sales","customer"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no marketing/sales-cost table","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'No table records marketing or sales-team acquisition cost -- the number of customers acquired is countable (erp_customers), but there is no cost figure anywhere to divide by it.', 'system'),
  (NULL, 'Lifetime Value (LTV)', 'Total invoiced revenue per customer, from erp_sales_invoices grouped by customer_id.', 'software_analysis', '["sales","customer","revenue"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"erp_sales_invoices","tableKey":"erp_sales_invoices","aggregation":"sum","groupByColumn":"customerId","aggregationColumnKey":"grandTotal"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Average Deal Size', 'Average grand_total of completed sales orders.', 'software_analysis', '["sales"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"erp_sales_orders","tableKey":"erp_sales_orders","aggregation":"avg","aggregationColumnKey":"grandTotal","filterColumn":"status","filterValue":"completed"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Project Type Analysis', 'Residential vs Commercial split.', 'software_analysis', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no project-type/residential-vs-commercial field on crm_opportunities or clients","aggregation":"count"}'::jsonb, '["table","chart"]'::jsonb, 'data_gap', 'Neither crm_opportunities, erp_customers, nor clients has a project-type (residential/commercial) classification field.', 'system'),
  (NULL, 'Location-wise Sales Analysis', 'City/region performance.', 'software_analysis', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no city/region field on crm_leads, crm_opportunities, or erp_customers","aggregation":"count"}'::jsonb, '["table","chart"]'::jsonb, 'data_gap', 'City/state/region lives on erp_addresses (billing/shipping addresses), not on the sales entities themselves (crm_leads/crm_opportunities/erp_sales_orders) -- a location-wise sales rollup would need a join this wave does not wire.', 'system'),
  (NULL, 'Product/Service Mix Analysis', 'Revenue by item, from erp_sales_order_items.', 'software_analysis', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- erp_sales_order_items has no org_id column -- needs a join through erp_sales_orders, beyond the current single-table TABLE_REGISTRY aggregation","aggregation":"count"}'::jsonb, '["table","chart"]'::jsonb, 'planned', 'erp_sales_order_items (item/description/amount) is real, but it has no org_id of its own -- org-scoping requires a join through erp_sales_orders.org_id that the current TABLE_REGISTRY (single-table only) does not support. Real data, not yet wired.', 'system'),
  (NULL, 'Repeat Business Analysis', 'Repeat customer contribution to total completed orders.', 'software_analysis', '["sales","customer"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_formula', '{"kind":"formula","formulaKey":"repeat_customer_percentage"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Referral Performance Analysis', 'Referral effectiveness -- deal value and commission accrued, by partner.', 'software_analysis', '["sales","revenue"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_formula', '{"kind":"formula","formulaKey":"referral_revenue_summary"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Sales Forecast Accuracy', 'Forecast vs actual.', 'software_analysis', '["sales","predictive"]'::jsonb, 'monthly', '{"dayOfMonth":1}'::jsonb, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no historical forecast-snapshot table","aggregation":"count"}'::jsonb, '["table","chart"]'::jsonb, 'data_gap', 'No table stores a point-in-time forecast snapshot -- crm_opportunities only holds the CURRENT estimated_value/stage, so there is nothing to compare a past forecast against once the deal actually closes.', 'system'),
  (NULL, 'Follow-up Effectiveness', 'Impact of follow-ups on conversion.', 'software_analysis', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no follow-up event log","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'No follow-up/contact-attempt log exists anywhere in the schema to correlate against conversion outcomes.', 'system'),
  (NULL, 'Sales Activity Analysis', 'Calls, meetings, visits vs closures.', 'software_analysis', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no call/meeting/visit activity-type tracking (see Daily Sales Activity Report)","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'Same gap as Daily Sales Activity Report -- no activity-type tracking exists to correlate against closures.', 'system'),
  (NULL, 'Quotation Revision Analysis', 'Impact of revisions on success.', 'software_analysis', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no revision concept on erp_quotations (see Quotation Revision Report)","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'Same gap as Quotation Revision Report -- erp_quotations has no revision/version concept to analyze.', 'system'),
  (NULL, 'Competitor Loss Analysis', 'Deals lost to competitors.', 'software_analysis', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no competitor field anywhere","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'No table has a competitor-name or lost-to-competitor field -- crm_opportunities/erp_quotations track win/lost status only, never a reason or competitor.', 'system'),
  (NULL, 'Discount Analysis', 'Discounts vs win rate.', 'software_analysis', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no discount field on erp_quotation_items or erp_sales_order_items","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'Neither erp_quotation_items nor erp_sales_order_items has a discount_percent/discount_amount column -- only quantity/rate/amount. There is no discount figure anywhere to analyze against win rate.', 'system'),
  (NULL, 'Payment Terms Analysis', 'Customers broken down by default payment terms (days).', 'software_analysis', '["sales","customer"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"erp_customers","tableKey":"erp_customers","aggregation":"count","groupByColumn":"defaultPaymentTermsDays"}'::jsonb, '["table","chart"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Pending Deal Risk Analysis', 'Opportunities the existing Wave-75 AI CRM Intelligence scoring flagged as high-risk (low win probability or explicit risk factors).', 'ai_analysis', '["sales","predictive"]'::jsonb, 'weekly', '{"dayOfWeek":1}'::jsonb, 'deterministic_formula', '{"kind":"formula","formulaKey":"ai_opportunity_risk_summary"}'::jsonb, '["table"]'::jsonb, 'built', NULL, 'system'),
  (NULL, 'Lead Response Time Analysis', 'Time taken to contact leads.', 'software_analysis', '["sales"]'::jsonb, 'on_demand', NULL, 'deterministic_aggregation', '{"kind":"aggregation","tableLabel":"NOT BUILT -- no first-contacted-at timestamp on crm_leads","aggregation":"count"}'::jsonb, '["table"]'::jsonb, 'data_gap', 'crm_leads has created_at and a status column but no first-contacted-at (or any status-transition history) timestamp -- there is no way to measure time-to-first-contact from the current schema.', 'system'),
